package genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.mapper.VehicleFilterMapper; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.repository.VehicleFilterRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleFilterService { private final VehicleFilterRepository repository; private final VehicleFilterMapper mapper; public VehicleFilterService(VehicleFilterRepository repository,VehicleFilterMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleFilterResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleFilterResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleFilter", String.valueOf(id))); } public VehicleFilterResponse create(VehicleFilterUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleFilterResponse update(UUID id,VehicleFilterUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleFilter", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("VehicleFilter", String.valueOf(id)); } }
